const ICON_BULLET_BOOK       = "https://www.figma.com/api/mcp/asset/ade3351e-410d-49bc-a239-4761e066cfd1";
const ICON_BULLET_LINK       = "https://www.figma.com/api/mcp/asset/5d719730-7650-470e-b0aa-05bdda0aaa75";
