const IMG_FIN_LOGO_MARK      = "https://www.figma.com/api/mcp/asset/1d80b781-d725-4789-9a61-46ffed02ecee";
const IMG_FIN_SERVICE_AGENT  = "https://www.figma.com/api/mcp/asset/36ac43f1-c422-4789-b550-06e1166f033a";
