type AgentMsg = {
  id: string;
  role: 'user' | 'assistant' | 'approval';
  content: string;
  toolCalls?: { toolName: string; args: any; result: any; durationMs: number }[];
  proposalId?: string;
  approvalPayload?: { toolName: string; preview: string; payload: any };
  approvalStatus?: 'pending' | 'approved' | 'rejected';
  createdAt: string;
};

